from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True, slots=True)
class IdentityInteraction:
    key: str
    style: str
    line: str
    skill_tag: str | None
    skill: str | None
    dc: int | None
    context: str
    success_text: str
    failure_text: str
    xp: int = 0
    gold: int = 0
    clue: str = ""
    journal: str = ""


